374:         // otherwise the escaping vars would be captured by the binder
375:         // debug_assert!(!self_ty.has_escaping_bound_vars());
376: 
377:         TraitRef::new(interner, self.def_id, [self_ty.into()].into_iter().chain(self.args.iter()))
