        use crate::ty::ExistentialPredicate::*;
        match self {
            ty::ExistentialPredicate::Trait(existential_trait_ref) => {
                Trait(existential_trait_ref.stable(tables, cx))
            }
            ty::ExistentialPredicate::Projection(existential_projection) => {
